+/**
+ * Test that is only run locally and is skipped on CI.
+ */
+module.exports.getSkipCISuite = function () {
+  if (window.__env__.TEST_ENV === 'ci') {
+    return suite.skip;
+  } else {
+    return suite;
+  }
+};

